ul.li:
convey
Evidence, Endorsements, and Reference Values in certificates and Certificate Revocation List (CRL) 
	extensions ;

embed Attestation Results or Evidence as
first-class authentication credentials in TLS handshake messages
	 ;

section.sourcecode:
$cbor-tag /= tag-cm-cbor<1668612069, my-evidence>

my-evidence = {
  &(eat_nonce: 10) => bytes .size (8..64)
}

figure.sourcecode:
json-collection = {
  ? "__cmwc_t": ~uri / oid
  + &(label: text) => json-cmw
}

cbor-collection = {
  ? "__cmwc_t": ~uri / oid
  + &(label: (int / text)) => cbor-cmw
}

section.sourcecode:
func exampleCMWTypeDemux(b []byte) CMWType { if len(b) == 0 { return Unknown }
switch b[0] { case 0x82: // 2-elements cbor-record (w/o ind field) case 0x83: // 3-elements cbor-record (w/ ind field) case 0x9f: // start of cbor-record using indefinite-length encoding return CBORRecord case 0xda: // tag-cm-cbor (CBOR tag in the TN range) return CBORTag case 0x5b: // ASCII '[', start of json-record return JSONRecord case 0x7b: // ASCII '{', start of json-collection return JSONCollection case 0xa0..0xbb: // CBOR map start values, start of cbor-collection case 0xbf: // ditto return CBORCollection }
return Unknown }

signed-cbor-cmw-protected-hdr = {
  1 => int                            ; alg
  3 => "application/cmw+cbor" / 273   ; cty
  * cose.label => cose.values
}

signed-cbor-cmw-unprotected-hdr = {
  * cose.label => cose.values
}

cose.label = int / text
cose.values = any

signed-json-cmw-protected-hdr = {
  "alg": text
  "cty": "application/cmw+json"
  * text => text
}

signed-json-cmw-unprotected-hdr = {
  * text => text
}

id-pe-cmw  OBJECT IDENTIFIER ::=
        { iso(1) identified-organization(3) dod(6) internet(1)
          security(5) mechanisms(5) pkix(7) id-pe(1) 35 }

CMW ::= CHOICE {
    json UTF8String,
    cbor OCTET STRING
}

CMWExtn { iso(1) identified-organization(3) dod(6) internet(1) security(5) mechanisms(5) pkix(7) id-mod(0) id-mod-cmw-extn(123) }
DEFINITIONS IMPLICIT TAGS ::= BEGIN
IMPORTS EXTENSION FROM PKIX-CommonTypes-2009 -- RFC 5912 { iso(1) identified-organization(3) dod(6) internet(1) security(5) mechanisms(5) pkix(7) id-mod(0) id-mod-pkixCommon-02(57) } ;
-- CMW Extension
ext-CMW EXTENSION ::= { SYNTAX CMW IDENTIFIED BY id-pe-cmw }
-- CMW Extension OID
id-pe-cmw OBJECT IDENTIFIER ::= { iso(1) identified-organization(3) dod(6) internet(1) security(5) mechanisms(5) pkix(7) id-pe(1) 35 }
-- CMW Extension Syntax
CMW ::= CHOICE { json UTF8String, cbor OCTET STRING }
END

{
  "__cmwc_t": "tag:example.com,2024:another-composite-attester",
  "attester A": [
    "application/eat-ucs+json",
    "e30K",
    4
  ],
  "attester B": [
    "application/eat-ucs+cbor",
    "oA",
    4
  ]
}

{
